import fs from 'node:fs';
import path from 'node:path';
import { AEGIS_DIR, REPO, die, ok, writeJ, has } from '../lib/util.js';
import { SCHEMA_VERSION, configP, stateP, transP } from '../lib/state.js';
import { defaultTransitions } from '../templates/transitions.js';
import { doctor } from '../lib/detect.js';
import { installHooks } from '../lib/hooks.js';
import { runInterview } from '../lib/interview.js';
import { fileURLToPath } from 'node:url';
const PKG_ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..', '..');
function copyDir(src, dst) {
    let n = 0;
    if (!fs.existsSync(src))
        return 0;
    fs.mkdirSync(dst, { recursive: true });
    for (const f of fs.readdirSync(src)) {
        const s2 = path.join(src, f), d2 = path.join(dst, f);
        if (fs.statSync(s2).isDirectory())
            n += copyDir(s2, d2);
        else {
            fs.copyFileSync(s2, d2);
            n++;
        }
    }
    return n;
}
const BRAIN_DIRS = ['architecture', 'context', 'quality', 'roadmap', 'execution', 'design', 'personas'];
export async function init(args) {
    if (!fs.existsSync(path.join(REPO, '.git')))
        die(1, 'Not a git repo');
    if (fs.existsSync(AEGIS_DIR) && !args.includes('--overwrite'))
        die(2, '.aegis already exists - pass --overwrite to reinitialize');
    fs.rmSync(AEGIS_DIR, { recursive: true, force: true });
    const doc = doctor();
    for (const d of ['checkpoints', 'ast', 'gates'])
        fs.mkdirSync(path.join(AEGIS_DIR, d), { recursive: true });
    for (const d of BRAIN_DIRS)
        fs.mkdirSync(path.join(REPO, 'brain', d), { recursive: true });
    // .gitignore: machine state NEVER enters git history (A1.4)
    const gi = path.join(REPO, '.gitignore');
    const prev = fs.existsSync(gi) ? fs.readFileSync(gi, 'utf8') : '';
    if (!prev.split('\n').includes('.aegis/'))
        fs.writeFileSync(gi, (prev && !prev.endsWith('\n') ? prev + '\n' : prev) + '.aegis/\n');
    writeJ(transP, defaultTransitions());
    const config = await runInterview(doc, args.includes('--yes'));
    writeJ(configP, config);
    // Lane cap (N5): human comfort cap throttled by RAM. lane_costs_mb prices one
    // full lane (browser_e2e + dev_server + codegen); ram_mb is total RAM recorded
    // by doctor (free RAM fluctuates too much to bake into persisted state).
    // Fallback when lane_costs_mb is absent/zero: the historical default of 2.
    const perLaneMb = (config.lane_costs_mb?.browser_e2e ?? 0) +
        (config.lane_costs_mb?.dev_server ?? 0) + (config.lane_costs_mb?.codegen ?? 0);
    const laneMax = perLaneMb > 0
        ? Math.min(config.human_lane_cap, Math.max(1, Math.floor(config.ram_mb / perLaneMb)))
        : 2;
    writeJ(stateP, {
        schema_version: SCHEMA_VERSION,
        current_skill: '00a',
        history: [], loop_counters: {}, state_visits: {},
        gates: {}, lanes: { max: laneMax, active: [] }, contracts_merged: false,
    });
    fs.writeFileSync(path.join(REPO, 'brain', 'context-window.md'), '# Context Window\n<!-- <=4k tokens; regenerated by aegis sync -->\n');
    fs.writeFileSync(path.join(REPO, 'brain', 'architecture', 'module-map.md'), '# Module Map\n<!-- GENERATED BY aegis ast build - DO NOT HAND-EDIT -->\n');
    // install skill files (refresh target for aegis sync) + brain templates
    const nSkills = copyDir(path.join(PKG_ROOT, 'skills'), path.join(AEGIS_DIR, 'skills'));
    const nTpl = copyDir(path.join(PKG_ROOT, 'templates', 'brain'), path.join(REPO, 'brain'));
    const hooks = installHooks();
    ok(`Aegis initialized (env ${config.environment_level}, platform ${config.platform}, RAM ${doc.ram_free_mb}/${doc.ram_total_mb} MB free)`);
    ok(`git hooks installed: ${hooks.join(', ')}`);
    ok(`skills installed: ${nSkills} files -> .aegis/skills/ | brain templates: ${nTpl} files`);
    if (config.project_type === 'brownfield')
        console.log('-> brownfield detected: run 00d reverse-discovery next (aegis transition 00d)');
}
export function doctorCmd(args) {
    const r = doctor();
    console.log(JSON.stringify(r, null, 2));
    if (args.includes('--save') && fs.existsSync(configP)) {
        const cfg = JSON.parse(fs.readFileSync(configP, 'utf8'));
        cfg.environment_level = r.environment_level;
        cfg.ram_mb = r.ram_total_mb;
        fs.writeFileSync(configP, JSON.stringify(cfg, null, 2) + '\n');
        ok('config updated from doctor');
    }
    if (r.worktrees_pruned)
        ok('stale worktrees pruned (A1.6)');
    if (!has('tsc') && !has('npx'))
        console.log('warn: no tsc/npx found - typecheck hooks will degrade');
}
